const raw = $json.reagendamiento;
let parsed = null;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  return [{ json: { ...$json, reagendamiento: 'ERROR_FECHA_INVALIDA' } }];
}

if (!parsed || parsed.tipo === 'null') {
  return [{ json: { ...$json, reagendamiento: null } }];
}

if (parsed.tipo === 'ERROR') {
  return [{ json: { ...$json, reagendamiento: 'ERROR_FECHA_INVALIDA' } }];
}

const tz = 'America/Guayaquil';
const ahora = new Date(new Date().toLocaleString('en-US', { timeZone: tz }));
let fecha = new Date(ahora);

function parseHora(horaStr) {
  if (!horaStr) return null;
  const h = horaStr.toLowerCase().trim();
  const match = h.match(/^(\d{1,2})\s*(am|pm)$/);
  if (!match) return null;
  let hour = parseInt(match[1], 10);
  const meridian = match[2];
  if (meridian === 'pm' && hour !== 12) hour += 12;
  if (meridian === 'am' && hour === 12) hour = 0;
  return hour;
}

if (parsed.tipo === 'relativo') {
  if (parsed.minutos_relativos) {
    fecha = new Date(ahora.getTime() + parsed.minutos_relativos * 60000);
  } else if (parsed.horas_relativas) {
    fecha = new Date(ahora.getTime() + parsed.horas_relativas * 3600000);
  }
} else if (parsed.tipo === 'hoy') {
  if (parsed.hora) {
    const h = parseHora(parsed.hora);
    if (h !== null) {
      fecha.setHours(h, 0, 0, 0);
    }
  }
  if (fecha.getTime() < ahora.getTime()) {
    fecha.setDate(fecha.getDate() + 1);
  }
} else if (parsed.tipo === 'mañana') {
  fecha.setDate(fecha.getDate() + 1);
  if (parsed.hora) {
    const h = parseHora(parsed.hora);
    if (h !== null) {
      fecha.setHours(h, 0, 0, 0);
    }
  }
} else if (parsed.tipo === 'fecha_fija') {
  const meses = {
    'enero': 0, 'febrero': 1, 'marzo': 2, 'abril': 3,
    'mayo': 4, 'junio': 5, 'julio': 6, 'agosto': 7,
    'septiembre': 8, 'octubre': 9, 'noviembre': 10, 'diciembre': 11
  };

  if (parsed.dia_numero) fecha.setDate(parsed.dia_numero);
  if (parsed.mes) {
    const m = meses[parsed.mes.toLowerCase()];
    if (m !== undefined) fecha.setMonth(m);
  }
  if (parsed.hora) {
    const h = parseHora(parsed.hora);
    if (h !== null) fecha.setHours(h, 0, 0, 0);
  }

  if (parsed.dia_nombre) {
    const diasUtf = {
      'lunes': 1, 'martes': 2, 'miercoles': 3, 'miércoles': 3,
      'jueves': 4, 'viernes': 5, 'sabado': 6, 'sábado': 6, 'domingo': 0
    };
    const diaTarget = diasUtf[parsed.dia_nombre.toLowerCase()];
    if (diaTarget !== undefined) {
      const diaActual = fecha.getDay();
      let diff = diaTarget - diaActual;
      if (diff <= 0) diff += 7;
      fecha.setDate(fecha.getDate() + diff);
    }
  }
}

if (isNaN(fecha.getTime())) {
  return [{ json: { ...$json, reagendamiento: 'ERROR_FECHA_INVALIDA' } }];
}

return [{ json: { ...$json, reagendamiento: fecha.toISOString() } }];

/*
 * CONSTRUYE SIP URI PARA TRANSFERENCIA CIEGA (blind transfer)
 * -----------------------------------------------------------
 * PROPOSITO: Cuando VAPI solicita un destino de transferencia
 * (transfer-destination-request), este nodo construye un SIP URI
 * con los datos del cliente para enrutar la llamada al operador.
 *
 * FORMULA: sip:{sip}_{nuic}_{id_registro}_{id_campania}@trunk
 * con headers X-Id-* para trazabilidad en el PBX.
 *
 * MODO: blind-transfer (transfiere sin consultar disponibilidad)
 * HABILITADO: sipHeadersInReferToEnabled para pasar metadata
 */
// n8n recibe un array, extraer primer elemento
const data = Array.isArray($input.item.json) ? $input.item.json[0] : $input.item.json;

// Extraer valores directamente
const id_registro = encodeURIComponent(data.id_registro || "0");
const id_campania = encodeURIComponent(data.id_campania || "0");
const nuic = encodeURIComponent(data.nuic || "0");
const sip = encodeURIComponent(data.sip || "0");
// Construir sipUri con query params
const sipUri = `sip:${sip}_${nuic}_${id_registro}_${id_campania}@vapisiptrunk.plusservices.ec?&X-Id-nuic=${nuic}&X-Id-Registro=${id_registro}&X-Id-Campania=${id_campania}`;

//const sipUri = `sip:80091-${nuic}-${id_registro}-${id_campania}@vapisiptrunk.plusservices.ec?X-Id-Registro=${id_registro}&X-Id-Campania=${id_campania}`;


console.log("📊 ID Registro:", id_registro, "| ID Campaña:", id_campania);
console.log("📞 SIP URI:", sipUri);

// Devolver array con un solo elemento (n8n lo enviará como el primer item)
return [{
  json: {
    destination: {
      type: "sip",
      sipUri: sipUri,
      transferPlan: {
        mode: "blind-transfer",
        sipHeadersInReferToEnabled: true
      }
    }
  }
}];

