function repairClassification(idNom, idMotivo){

  idNom = num(idNom, 7);

  idMotivo =
    idMotivo === null
      ? null
      : num(idMotivo, 42);

  if (idNom === 1) {

    return {
      id_nomenclatura: 1,
      id_motivo: null,
      repaired: true,
      repair_reason: 'acceptance_without_motive'
    };
  }

  if (!VALID[idNom]) {

    return {
      id_nomenclatura: 7,
      id_motivo: 42,
      repaired: true,
      repair_reason: 'invalid_nomenclatura'
    };
  }

  if (VALID[idNom].includes(idMotivo)) {

    return {
      id_nomenclatura: idNom,
      id_motivo: idMotivo,
      repaired: false
    };
  }

  const correctedNom =
    MOTIVE_TO_NOMENCLATURA[idMotivo];

  if (correctedNom) {

    return {
      id_nomenclatura: correctedNom,
      id_motivo: idMotivo,
      repaired: true,
      repair_reason:
        'motive_belongs_to_other_nomenclatura'
    };
  }

  const fallbackByNom = {

    2: 2029,
    3: 20,
    4: 1005,
    5: 38,
    6: 39,
    7: 42
  };

  return {

    id_nomenclatura: idNom,

    id_motivo:
      fallbackByNom[idNom] || 42,

    repaired: true,

    repair_reason:
      'fallback_default_motive'
  };
