function mapToCanonical(input) {

  const src = Array.isArray(input)
    ? input[0]
    : input;

  const rawContent = (
    src?.message?.content ||
    src?.choices?.[0]?.message?.content ||
    src?.content ||
    src?.transcript ||
    ""
  );

  /* =====================
     KB DETECTION
  ===================== */

  const kbResult =
    detectFromKnowledgeBase(rawContent);

  if (kbResult) {

    return {

      id_nomenclatura:
        kbResult.id_nomenclatura,

      id_motivo:
        kbResult.id_motivo,

      telefono_field: null,

      telefono_index: null,

      repair_info: {
