      llm_valido: true,

      llm_source:
        'knowledge_base',

      llm_raw:
        rawContent,

      llm_clean: null
    };
  }

  /* =====================
     JSON PARSE
  ===================== */

  let etiqueta =
    parseJSONLoose(rawContent);

  /* =====================
     SAFE EXTRACTION
  ===================== */

  if (!etiqueta) {

    const extracted =
      extractFirstJSONObject(rawContent);

    if (extracted) {

      etiqueta =
        parseJSONLoose(extracted);
    }
  }

  /* =====================
     FALLBACK
  ===================== */

  if (
    !etiqueta ||
    typeof etiqueta !== 'object' ||
    Array.isArray(etiqueta)
  ) {

    etiqueta = {
      id_nomenclatura: 7,
      id_motivo: 42
    };
  }

  let idNom =
    etiqueta.id_nomenclatura;

  let idMotivo =
    etiqueta.hasOwnProperty('id_motivo')
      ? etiqueta.id_motivo
      : 42;

  /* =====================
     AUTO REPAIR
  ===================== */

  const repaired =
    repairClassification(
      idNom,
      idMotivo
    );

  idNom = repaired.id_nomenclatura;
  idMotivo = repaired.id_motivo;

  /* =====================
     PHONE FIELD
  ===================== */

  const phoneField =
    Object.keys(etiqueta)
      .find(k => /^ph_/i.test(k));

  return {

    id_nomenclatura: idNom,

    id_motivo: idMotivo,

    telefono_field:
      phoneField || null,

    telefono_index:
      phoneField &&
      Number.isFinite(+etiqueta[phoneField])
        ? +etiqueta[phoneField]
        : null,

    repair_info: repaired,

    kb_detected: null,

    llm_valido: true,

    llm_source: 'json',

    llm_raw: rawContent,

    llm_clean: etiqueta
  };
}

