function buildFlowState(canonical, original){

  const now = new Date();

  const currentTries =
    num(original?.win_tries, 0);

  const maxIntentos =
    num(original?.max_intentos, 5);

  const nextTry30m =
    new Date(
      now.getTime() + (30 * 60 * 1000)
    ).toISOString();

  const nextTry2h =
    new Date(
      now.getTime() + (2 * 60 * 60 * 1000)
    ).toISOString();

  const nextTry24h =
    new Date(
      now.getTime() + (24 * 60 * 60 * 1000)
    ).toISOString();

  /* =====================
     COUNT REAL ATTEMPTS
  ===================== */

  const shouldCountAttempt =
    [1,2,3,4,5,6,7]
      .includes(
        canonical.id_nomenclatura
      );

  const newTryCount =
    shouldCountAttempt
      ? currentTries + 1
      : currentTries;

  /* =====================
     MAX RETRIES
  ===================== */

  if (
    newTryCount >= maxIntentos
  ) {

    return {

      status_flujo:
        'agotado_hoy',

      prioridad_actual:
        -2,

      reintentar_iso:
        null,

      max_intentos:
        maxIntentos,

      intentos_llamada:
        newTryCount,

