        newTryCount,

      last_try_ymd:
        now.toISOString().slice(0,10),

      _decision_path:
        'MAX_RETRIES_REACHED'
    };
  }

  const result = {

    status_flujo: 'pendiente',

    prioridad_actual: 0,

    reintentar_iso: null,

    max_intentos: maxIntentos,

    intentos_llamada:
      newTryCount,

    win_tries:
      newTryCount,

    last_try_ymd:
      now.toISOString().slice(0,10),

    _decision_path: null
  };

  const nom =
    canonical.id_nomenclatura;

  const motivo =
    canonical.id_motivo;

  /* =====================
     ACCEPTED TRANSFER
  ===================== */

  if (nom === 1) {

    result.status_flujo =
      'finalizado_ok';

    result.prioridad_actual =
      10;

    result._decision_path =
      'ACCEPT_TRANSFER';

    return result;
  }

  /* =====================
     NEGATIVE CONTACT
  ===================== */

  if (nom === 2) {

    result.status_flujo =
      'rechazado';

    result.prioridad_actual =
      -5;

    result._decision_path =
      'NEGATIVE_CONTACT';

    return result;
