  /* =====================
     WRONG PERSON
  ===================== */

  if (nom === 3) {

    result.status_flujo =
      'rechazado';

    result.prioridad_actual =
      -4;

    result._decision_path =
      'WRONG_PERSON';

    return result;
  }

  /* =====================
     NO CONTACT
  ===================== */

  if (nom === 4) {

    result.status_flujo =
      'reintentar';

    result.prioridad_actual =
      5;

    result.reintentar_iso =
      nextTry2h;

    result._decision_path =
      'NO_CONTACT';

    return result;
  }

  /* =====================
     CALLBACK
  ===================== */

  if (nom === 5) {

    result.status_flujo =
      'reintentar';

    result.prioridad_actual =
      8;

    result.reintentar_iso =
      nextTry30m;

    result._decision_path =
      'CALLBACK';

    return result;
  }

  /* =====================
     TECHNICAL
  ===================== */

  if (nom === 6) {

    result.status_flujo =
      'reintentar';

    result.prioridad_actual =
      2;

    result.reintentar_iso =
      nextTry24h;

    result._decision_path =
      'TECHNICAL';

    return result;
  }

  /* =====================
     INVALID / MACHINE
  ===================== */

  if (nom === 7) {

    /* =====================
       VOICEMAIL
    ===================== */

    if (motivo === 41) {

      result.status_flujo =
        'reintentar';

      result.prioridad_actual =
        3;

      result.reintentar_iso =
        nextTry2h;

      result._decision_path =
        'VOICEMAIL';

      return result;
    }

    /* =====================
       BUSY
    ===================== */

    if (motivo === 43) {

      result.status_flujo =
        'reintentar';

      result.prioridad_actual =
        6;

      result.reintentar_iso =
        nextTry30m;

      result._decision_path =
        'BUSY';

      return result;
    }

    /* =====================
       FAX
    ===================== */

    if (motivo === 44) {

      result.status_flujo =
        'agotado';

      result.prioridad_actual =
        -10;

      result._decision_path =
        'FAX';

      return result;
    }

    /* =====================
       INVALID NUMBER
    ===================== */

    result.status_flujo =
      'agotado';

    result.prioridad_actual =
      -10;

    result._decision_path =
      'INVALID_PHONE';

    return result;
  }

  /* =====================
     FALLBACK
  ===================== */

  result.status_flujo =
    'pendiente';

  result.prioridad_actual =
    0;

  result._decision_path =
    'UNKNOWN';

  return result;
}

