      kb_detected: 'NO_TRANSFER'
    };
  }

  if (
    KB.callback.some(p =>
      t.includes(normalizeText(p))
    )
  ) {

    return {
      id_nomenclatura: 5,
      id_motivo: 38,
      kb_detected: 'CALLBACK'
    };
  }

  if (
    KB.voicemail.some(p =>
      t.includes(normalizeText(p))
    )
  ) {

    return {
      id_nomenclatura: 7,
      id_motivo: 41,
      kb_detected: 'VOICEMAIL'
    };
  }

  if (
    KB.busy.some(p =>
      t.includes(normalizeText(p))
    )
  ) {

    return {
      id_nomenclatura: 7,
      id_motivo: 43,
      kb_detected: 'BUSY'
    };
  }

  if (
    KB.fax.some(p =>
      t.includes(normalizeText(p))
    )
  ) {

    return {
      id_nomenclatura: 7,
      id_motivo: 44,
      kb_detected: 'FAX'
    };
  }

  return null;
}

/* ===================== REPAIRER ===================== */

function repairClassification(idNom, idMotivo){

  idNom = num(idNom, 7);

  idMotivo =
    idMotivo === null
      ? null
      : num(idMotivo, 42);

  if (idNom === 1) {

    return {
      id_nomenclatura: 1,
      id_motivo: null,
      repaired: true,
      repair_reason: 'acceptance_without_motive'
    };
  }

  if (!VALID[idNom]) {

    return {
      id_nomenclatura: 7,
      id_motivo: 42,
      repaired: true,
      repair_reason: 'invalid_nomenclatura'
    };
  }

  if (VALID[idNom].includes(idMotivo)) {

    return {
      id_nomenclatura: idNom,
      id_motivo: idMotivo,
      repaired: false
    };
  }

  const correctedNom =
    MOTIVE_TO_NOMENCLATURA[idMotivo];

  if (correctedNom) {

    return {
      id_nomenclatura: correctedNom,
      id_motivo: idMotivo,
      repaired: true,
      repair_reason:
        'motive_belongs_to_other_nomenclatura'
    };
  }

  const fallbackByNom = {

    2: 2029,
    3: 20,
    4: 1005,
    5: 38,
    6: 39,
    7: 42
  };

  return {

    id_nomenclatura: idNom,

    id_motivo:
      fallbackByNom[idNom] || 42,

    repaired: true,

    repair_reason:
      'fallback_default_motive'
  };
}

/* ===================== MAP TO CANONICAL ===================== */

function mapToCanonical(input) {

  const src = Array.isArray(input)
    ? input[0]
    : input;

  const rawContent = (
    src?.message?.content ||
    src?.choices?.[0]?.message?.content ||
    src?.content ||
    src?.transcript ||
    ""
  );

  /* =====================
     KB DETECTION
  ===================== */

  const kbResult =
    detectFromKnowledgeBase(rawContent);

  if (kbResult) {

    return {

      id_nomenclatura:
        kbResult.id_nomenclatura,

      id_motivo:
        kbResult.id_motivo,

      telefono_field: null,

      telefono_index: null,

      repair_info: {
        repaired: false,
        repair_reason: null
      },

      kb_detected:
        kbResult.kb_detected,

      llm_valido: true,

      llm_source:
        'knowledge_base',

      llm_raw:
        rawContent,

      llm_clean: null
    };
  }

  /* =====================
     JSON PARSE
  ===================== */

  let etiqueta =
    parseJSONLoose(rawContent);

  /* =====================
     SAFE EXTRACTION
  ===================== */

  if (!etiqueta) {

    const extracted =
      extractFirstJSONObject(rawContent);

    if (extracted) {

      etiqueta =
        parseJSONLoose(extracted);
    }
  }

  /* =====================
     FALLBACK
  ===================== */

  if (
    !etiqueta ||
    typeof etiqueta !== 'object' ||
    Array.isArray(etiqueta)
  ) {

    etiqueta = {
      id_nomenclatura: 7,
      id_motivo: 42
    };
  }

  /* =====================
     RAW VALUES
  ===================== */

  let idNom =
    etiqueta.id_nomenclatura;

  let idMotivo =
    etiqueta.hasOwnProperty('id_motivo')
      ? etiqueta.id_motivo
      : 42;

  /* =====================
     AUTO REPAIR
  ===================== */

  const repaired =
    repairClassification(
      idNom,
      idMotivo
    );

  idNom = repaired.id_nomenclatura;
  idMotivo = repaired.id_motivo;

  /* =====================
     PHONE FIELD
  ===================== */

  const phoneField =
    Object.keys(etiqueta)
      .find(k => /^ph_/i.test(k));

  return {

    id_nomenclatura: idNom,

    id_motivo: idMotivo,

    telefono_field:
      phoneField || null,

    telefono_index:
      phoneField &&
      Number.isFinite(+etiqueta[phoneField])
        ? +etiqueta[phoneField]
        : null,

    repair_info: repaired,

    kb_detected: null,

    llm_valido: true,

    llm_source: 'json',

    llm_raw: rawContent,

    llm_clean: etiqueta
  };
}

/* ===================== FLOW DECISION ENGINE ===================== */

function buildFlowState(canonical, original){

  const now = new Date();

  const currentTries =
    num(original?.win_tries, 0);

  const maxIntentos =
    num(original?.max_intentos, 5);

  const nextTry30m =
    new Date(
      now.getTime() + (30 * 60 * 1000)
    ).toISOString();

  const nextTry2h =
    new Date(
      now.getTime() + (2 * 60 * 60 * 1000)
    ).toISOString();

  const nextTry24h =
    new Date(
      now.getTime() + (24 * 60 * 60 * 1000)
    ).toISOString();

  const result = {

    /* =====================
       VALID DB STATUS
    ===================== */

    status_flujo: 'pendiente',

    /* =====================
       VALID PRIORITY
       RANGE -10 to 10
    ===================== */

    prioridad_actual: 0,

    reintentar_iso: null,

    max_intentos: maxIntentos,

    /* =====================
       REAL ATTEMPTS
    ===================== */

    intentos_llamada:
      currentTries + 1,

    win_tries:
      currentTries + 1,

    last_try_ymd:
      now.toISOString().slice(0,10),

    _decision_path: null
  };

  const nom =
    canonical.id_nomenclatura;

  const motivo =
    canonical.id_motivo;

  /* =====================
     ACCEPTED TRANSFER
  ===================== */

  if (nom === 1) {

    result.status_flujo =
      'finalizado_ok';

    result.prioridad_actual =
      10;

    result._decision_path =
      'ACCEPT_TRANSFER';

    return result;
  }

  /* =====================
     NEGATIVE CONTACT
  ===================== */

  if (nom === 2) {

    result.status_flujo =
      'rechazado';

    result.prioridad_actual =
      -5;

    result._decision_path =
      'NEGATIVE_CONTACT';

    return result;
  }

  /* =====================
     WRONG PERSON
  ===================== */

  if (nom === 3) {

    result.status_flujo =
      'rechazado';

    result.prioridad_actual =
      -4;

    result._decision_path =
      'WRONG_PERSON';

    return result;
  }

  /* =====================
     NO CONTACT
  ===================== */

  if (nom === 4) {

    result.status_flujo =
      'reintentar';

    result.prioridad_actual =
      5;

    result.reintentar_iso =
      nextTry2h;

    result._decision_path =
      'NO_CONTACT';

    return result;
  }

  /* =====================
     CALLBACK
  ===================== */

  if (nom === 5) {

    result.status_flujo =
      'reintentar';

    result.prioridad_actual =
      8;

    result.reintentar_iso =
      nextTry30m;

    result._decision_path =
      'CALLBACK';

    return result;
  }

  /* =====================
     TECHNICAL
  ===================== */

  if (nom === 6) {

    result.status_flujo =
      'reintentar';

    result.prioridad_actual =
      2;

    result.reintentar_iso =
      nextTry24h;

    result._decision_path =
      'TECHNICAL';

    return result;
  }

  /* =====================
     INVALID PHONE
  ===================== */

  if (nom === 7) {

    result.status_flujo =
      'agotado';

    result.prioridad_actual =
      -10;

    result._decision_path =
      'INVALID_PHONE';

    return result;
  }

  /* =====================
     MAX RETRIES
  ===================== */

  if (
    currentTries + 1 >= maxIntentos
  ) {

    result.status_flujo =
      'agotado_hoy';

    result.prioridad_actual =
      -2;

    result._decision_path =
      'MAX_RETRIES_REACHED';

    return result;
  }

  /* =====================
     FALLBACK
  ===================== */

  result.status_flujo =
    'pendiente';

  result.prioridad_actual =
    0;

  result._decision_path =
    'UNKNOWN';

  return result;
}

