/*
 * EXTRAE PROMPT Y CONTEXTO DE LA CONVERSACION
 * ===========================================
 * PROPOSITO: Del payload de VAPI, extrae:
 *  1. prompt: el ultimo mensaje del usuario (objecion actual)
 *  2. context: la conversacion completa formateada como
 *     "ROLE: contenido" para que el AI AGENT: CLASIFICA OBJECIONES Y BUSCA RESPUESTA EN BD (Agente + HERRAMIENTA PG DEL AGENTE: busca en callcenter_objeciones_asistenciaTool) tenga memoria
 *
 * USA: messagesOpenAIFormatted del artifact de VAPI
 * BUSCA: ultimo mensaje con role='user' como prompt
 * FORMATEA: todos los mensajes assistant/user como contexto
 *
 * OUTPUT: { prompt, context } -> alimenta al AI AGENT: CLASIFICA OBJECIONES Y BUSCA RESPUESTA EN BD (Agente + HERRAMIENTA PG DEL AGENTE: busca en callcenter_objeciones_asistenciaTool)
 */const data = $input.first().json;

const messages =
  data.body.message.artifact.messagesOpenAIFormatted || [];

// Último mensaje del usuario
const lastUserMessage =
  [...messages]
    .reverse()
    .find(m => m.role === 'user');

// Contexto conversacional limpio
const context = messages
  .filter(m =>
    ['assistant', 'user'].includes(m.role)
  )
  .map(m => {
    return `${m.role.toUpperCase()}: ${m.content || ''}`;
  })
  .join('\n');

// Prompt SOLO para retrieval
const prompt = lastUserMessage?.content || '';

return [
  {
    json: {
      prompt,
      context
    }
  }
];

/*
 * PARSEA JSON DE SALIDA DEL AI AGENT
 * ===================================
 * PROPOSITO: El AI AGENT: CLASIFICA OBJECIONES Y BUSCA RESPUESTA EN BD (Agente + HERRAMIENTA PG DEL AGENTE: busca en callcenter_objeciones_asistenciaTool) devuelve su respuesta como string
 * JSON dentro de item.json.output. Este nodo lo parsea
